     5→//! Garland command - celebrate heat completion and create continuation
     6→//!
     7→//! Garlanding a heat:
     8→//! - Updates source heat silks to garlanded form and status to stabled
     9→//! - Creates new heat with continuation silks, status racing
    10→//! - Transfers actionable paces (rough/bridled) to new heat
    11→//! - Retains complete/abandoned paces in garlanded heat
    12→
    13→use std::path::PathBuf;
    14→
    15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_GarlandArgs as LibGarlandArgs};
    16→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
    17→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
    18→
    19→/// Arguments for jjx_garland command
    20→#[derive(clap::Args, Debug)]
    21→pub struct jjrgl_GarlandArgs {
    22→    /// Path to the Gallops JSON file
    23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    24→    pub file: PathBuf,
    25→
    26→    /// Heat to garland (Firemark)
    27→    pub firemark: String,
    28→}
    29→
    30→/// Run the garland command
    31→///
    32→/// Executes garland operation, saves gallops, and commits the result.
    33→/// Returns exit code (0 for success, non-zero for failure).
    34→pub fn jjrgl_run_garland(args: jjrgl_GarlandArgs) -> i32 {
    35→    use std::path::Path;
    36→
    37→    // Acquire lock FIRST - fail fast if another operation is in progress
    38→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
    39→        Ok(l) => l,
    40→        Err(e) => {
    41→            eprintln!("jjx_garland: error: {}", e);
    42→            return 1;
    43→        }
    44→    };
    45→
    46→    let mut gallops = match Gallops::jjrg_load(&args.file) {
    47→        Ok(g) => g,
    48→        Err(e) => {
    49→            eprintln!("jjx_garland: error loading Gallops: {}", e);
    50→            return 1;
    51→        }
    52→    };
    53→
    54→    let firemark_str = args.firemark.clone();
    55→
    56→    // Compute base path from gallops file
    57→    let base_path = args.file.parent()
    58→        .and_then(|p| p.parent())
    59→        .and_then(|p| p.parent())
    60→        .unwrap_or(Path::new("."));
    61→
    62→    let garland_args = LibGarlandArgs {
    63→        firemark: firemark_str.clone(),
    64→    };
    65→
    66→    // Execute garland operation
    67→    let result = match gallops.jjrg_garland(garland_args, base_path) {
    68→        Ok(r) => r,
    69→        Err(e) => {
    70→            eprintln!("jjx_garland: error: {}", e);
    71→            return 1;
    72→        }
    73→    };
    74→
    75→    // Save gallops
    76→    if let Err(e) = gallops.jjrg_save(&args.file) {
    77→        eprintln!("jjx_garland: error saving Gallops: {}", e);
    78→        return 1;
    79→    }
    80→
    81→    // Parse both firemarks for commit file list
    82→    let old_fm = Firemark::jjrf_parse(&result.old_firemark).expect("garland returned invalid old firemark");
    83→    let new_fm = Firemark::jjrf_parse(&result.new_firemark).expect("garland returned invalid new firemark");
    84→
    85→    let gallops_path = args.file.to_string_lossy().to_string();
    86→    let old_paddock_path = format!(".claude/jjm/jjp_{}.md", old_fm.jjrf_as_str());
    87→    let new_paddock_path = format!(".claude/jjm/jjp_{}.md", new_fm.jjrf_as_str());
    88→
    89→    // Build commit message using heat-level Garland action
    90→    let commit_message = format_heat_message(
    91→        &old_fm,
    92→        HeatAction::Garland,
    93→        &format!("{} → {}", result.old_silks, result.new_silks)
    94→    );
    95→
    96→    let commit_args = vvc::vvcm_CommitArgs {
    97→        files: vec![
    98→            gallops_path,
    99→            old_paddock_path,
   100→            new_paddock_path,
   101→        ],
   102→        message: commit_message,
   103→        size_limit: 100000,  // 100KB - paddock files can be large
   104→        warn_limit: 50000,
   105→    };
   106→
   107→    match vvc::machine_commit(&lock, &commit_args) {
   108→        Ok(hash) => {
   109→            eprintln!("jjx_garland: committed {}", &hash[..8]);
   110→        }
   111→        Err(e) => {
   112→            eprintln!("jjx_garland: commit warning: {}", e);
   113→        }
   114→    }
   115→
   116→    // Output JSON result
   117→    let output = serde_json::json!({
   118→        "old_firemark": result.old_firemark,
   119→        "old_silks": result.old_silks,
   120→        "new_firemark": result.new_firemark,
   121→        "new_silks": result.new_silks,
   122→        "paces_transferred": result.paces_transferred,
   123→        "paces_retained": result.paces_retained,
   124→    });
   125→
   126→    match serde_json::to_string_pretty(&output) {
   127→        Ok(json) => {
   128→            println!("{}", json);
   129→            0
   130→        }
   131→        Err(e) => {
   132→            eprintln!("jjx_garland: error serializing output: {}", e);
   133→            1
   134→        }
   135→    }
   136→    // lock released here
   137→}
