  1006→/// Restring - bulk draft multiple paces atomically
  1007→///
  1008→/// Moves multiple paces from source heat to destination heat in a single operation.
  1009→/// All paces are validated before any mutations occur.
  1010→/// Order is preserved in the destination heat.
  1011→pub fn jjrg_restring(gallops: &mut jjrg_Gallops, args: jjrg_RestringArgs) -> Result<jjrg_RestringResult, String> {
  1012→    // Parse and normalize firemarks
  1013→    let source_firemark = Firemark::jjrf_parse(&args.source_firemark)
  1014→        .map_err(|e| format!("Invalid source firemark: {}", e))?;
  1015→    let source_firemark_key = source_firemark.jjrf_display();
  1016→
  1017→    let dest_firemark = Firemark::jjrf_parse(&args.dest_firemark)
  1018→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
  1019→    let dest_firemark_key = dest_firemark.jjrf_display();
  1020→
  1021→    // Validate firemarks are different
  1022→    if source_firemark_key == dest_firemark_key {
  1023→        return Err("Cannot draft paces to same heat".to_string());
  1024→    }
  1025→
  1026→    // Validate both heats exist
  1027→    if !gallops.heats.contains_key(&source_firemark_key) {
  1028→        return Err(format!("Heat '{}' not found", source_firemark_key));
  1029→    }
  1030→    if !gallops.heats.contains_key(&dest_firemark_key) {
  1031→        return Err(format!("Heat '{}' not found", dest_firemark_key));
  1032→    }
  1033→
  1034→    // Validate coronet array is non-empty
  1035→    if args.coronets.is_empty() {
  1036→        return Err("No paces specified for draft".to_string());
  1037→    }
  1038→
  1039→    // Validate all coronets before any mutations
  1040→    let mut normalized_coronets = Vec::new();
  1041→    for coronet_str in &args.coronets {
  1042→        // Parse and normalize coronet
  1043→        let coronet = Coronet::jjrf_parse(coronet_str)
  1044→            .map_err(|e| format!("Invalid coronet '{}': {}", coronet_str, e))?;
  1045→        let coronet_key = coronet.jjrf_display();
  1046→
  1047→        // Verify coronet belongs to source heat
  1048→        let coronet_firemark = coronet.jjrf_parent_firemark();
  1049→        if coronet_firemark.jjrf_display() != source_firemark_key {
  1050→            return Err(format!(
  1051→                "Pace {} does not belong to source heat {}",
  1052→                coronet_key, source_firemark_key
  1053→            ));
  1054→        }
  1055→
  1056→        // Verify pace exists in source heat
  1057→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1058→        if !source_heat.paces.contains_key(&coronet_key) {
  1059→            return Err(format!(
  1060→                "Pace {} not found in heat {}",
  1061→                coronet_key, source_firemark_key
  1062→            ));
  1063→        }
  1064→
  1065→        normalized_coronets.push(coronet_key);
  1066→    }
  1067→
  1068→    // All validations passed - now perform the operations
  1069→
  1070→    // Capture source heat info before mutations
  1071→    let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1072→    let source_silks = source_heat.silks.clone();
  1073→    let source_paddock = source_heat.paddock_file.clone();
  1074→
  1075→    // Capture destination heat info
  1076→    let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
  1077→    let dest_silks = dest_heat.silks.clone();
  1078→    let dest_paddock = dest_heat.paddock_file.clone();
  1079→
  1080→    // Draft each pace to destination (preserving order)
  1081→    let mut mappings = Vec::new();
  1082→    for coronet_key in normalized_coronets {
  1083→        let draft_args = jjrg_DraftArgs {
  1084→            coronet: coronet_key.clone(),
  1085→            to: dest_firemark_key.clone(),
  1086→            before: None,
  1087→            after: None,
  1088→            first: false, // Append to end to preserve order
  1089→        };
  1090→
  1091→        // Get pace info before drafting (for output)
  1092→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
  1093→        let pace = source_heat.paces.get(&coronet_key).unwrap();
  1094→        let first_tack = pace.tacks.first();
  1095→        let silks = first_tack.map(|t| t.silks.clone()).unwrap_or_default();
  1096→        let state = first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough);
  1097→        let spec_full = first_tack.map(|t| t.text.clone()).unwrap_or_default();
  1098→        let spec_preview = if spec_full.len() > 80 {
  1099→            format!("{}...", &spec_full[..77])
  1100→        } else {
  1101→            spec_full.clone()
  1102→        };
  1103→
  1104→        // Perform the draft
  1105→        let result = jjrg_draft(gallops, draft_args)?;
  1106→
  1107→        mappings.push(jjrg_RestringMapping {
  1108→            old_coronet: coronet_key,
  1109→            new_coronet: result.new_coronet,
  1110→            silks,
  1111→            state,
  1112→            spec: spec_preview,
  1113→        });
  1114→    }
  1115→
  1116→    // Check if source heat is now empty
  1117→    let source_heat_after = gallops.heats.get(&source_firemark_key).unwrap();
  1118→    let source_empty_after = source_heat_after.paces.is_empty();
  1119→
  1120→    Ok(jjrg_RestringResult {
  1121→        source_firemark: source_firemark_key,
  1122→        source_silks,
  1123→        source_paddock,
  1124→        source_empty_after,
  1125→        dest_firemark: dest_firemark_key,
  1126→        dest_silks,
  1127→        dest_paddock,
  1128→        drafted: mappings,
  1129→    })
  1130→}
