    19→/// Resolve the default heat (first racing heat) when no target is specified
    20→pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    21→    for (heat_key, heat) in &gallops.heats {
    22→        if heat.status == HeatStatus::Racing {
    23→            return Ok(heat_key.clone());
    24→        }
    25→    }
    26→    Err("No racing heats found".to_string())
